"use client"

import React, { useState } from 'react';
import { useJournal } from '@/contexts/JournalContext';
import { JournalList } from './JournalList';
import { ChevronDown } from 'lucide-react';

export function JournalListCard() {
  const { entries, selectEntry, createEntry } = useJournal();
  const [collapsed, setCollapsed] = useState(false);

  const handleCreate = () => {
    const title = window.prompt('Enter journal title');
    if (title && title.trim()) {
      createEntry(title.trim());
    }
  };

  return (
    <div className="bg-white dark:bg-neutral-900 rounded-lg shadow p-6">
      <div
        className="flex items-center justify-between mb-4 cursor-pointer"
        onClick={() => setCollapsed(!collapsed)}
      >
        <h2 className="text-xl font-semibold text-foreground">Your Journals ({entries.length})</h2>
        <ChevronDown
          className={`h-5 w-5 text-neutral-400 transform transition-transform ${collapsed ? '-rotate-90' : 'rotate-0'}`}
        />
      </div>
      {!collapsed && (
        <JournalList
          entries={entries}
          onSelectEntry={(entry) => selectEntry(entry.id)}
          onCreateNew={handleCreate}
          searchQuery=""
        />
      )}
    </div>
  );
} 