"use client"

import { useState, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { vscDarkPlus } from 'react-syntax-highlighter/dist/esm/styles/prism';
import { Button } from "@/components/ui/button";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import {
  Bold,
  Italic,
  List,
  ListOrdered,
  Heading1,
  Heading2,
  Heading3,
  Code,
  Image,
  Link,
  Quote,
  Minus,
  Table,
} from 'lucide-react';

interface MarkdownEditorProps {
  content: string;
  onChange: (content: string) => void;
  onSave: () => void;
}

export function MarkdownEditor({ content, onChange, onSave }: MarkdownEditorProps) {
  const [isDirty, setIsDirty] = useState(false);
  const [activeTab, setActiveTab] = useState<'edit' | 'preview'>('edit');

  useEffect(() => {
    const handleKeyPress = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 's') {
        e.preventDefault();
        onSave();
      }
    };

    window.addEventListener('keydown', handleKeyPress);
    return () => window.removeEventListener('keydown', handleKeyPress);
  }, [onSave]);

  const insertMarkdown = (prefix: string, suffix: string = '') => {
    const textarea = document.querySelector('textarea');
    if (!textarea) return;

    const start = textarea.selectionStart;
    const end = textarea.selectionEnd;
    const selectedText = content.substring(start, end);
    const newContent = content.substring(0, start) + prefix + selectedText + suffix + content.substring(end);
    
    onChange(newContent);
    setIsDirty(true);
    
    // Set cursor position after the inserted markdown
    setTimeout(() => {
      textarea.focus();
      textarea.setSelectionRange(start + prefix.length, end + prefix.length);
    }, 0);
  };

  const formatButtons = [
    { icon: <Bold className="h-4 w-4" />, action: () => insertMarkdown('**', '**'), tooltip: 'Bold' },
    { icon: <Italic className="h-4 w-4" />, action: () => insertMarkdown('*', '*'), tooltip: 'Italic' },
    { icon: <Heading1 className="h-4 w-4" />, action: () => insertMarkdown('# '), tooltip: 'Heading 1' },
    { icon: <Heading2 className="h-4 w-4" />, action: () => insertMarkdown('## '), tooltip: 'Heading 2' },
    { icon: <Heading3 className="h-4 w-4" />, action: () => insertMarkdown('### '), tooltip: 'Heading 3' },
    { icon: <List className="h-4 w-4" />, action: () => insertMarkdown('- '), tooltip: 'Unordered List' },
    { icon: <ListOrdered className="h-4 w-4" />, action: () => insertMarkdown('1. '), tooltip: 'Ordered List' },
    { icon: <Code className="h-4 w-4" />, action: () => insertMarkdown('```\n', '\n```'), tooltip: 'Code Block' },
    { icon: <Image className="h-4 w-4" />, action: () => insertMarkdown('![alt text](', ')'), tooltip: 'Image' },
    { icon: <Link className="h-4 w-4" />, action: () => insertMarkdown('[', '](url)'), tooltip: 'Link' },
    { icon: <Quote className="h-4 w-4" />, action: () => insertMarkdown('> '), tooltip: 'Blockquote' },
    { icon: <Minus className="h-4 w-4" />, action: () => insertMarkdown('---\n'), tooltip: 'Horizontal Rule' },
    { icon: <Table className="h-4 w-4" />, action: () => insertMarkdown('| Header 1 | Header 2 |\n|----------|----------|\n| Cell 1   | Cell 2   |'), tooltip: 'Table' },
  ];

  return (
    <div className="flex flex-col h-full">
      <div className="flex items-center gap-2 p-2 border-b">
        {formatButtons.map((button, index) => (
          <Button
            key={index}
            variant="ghost"
            size="icon"
            onClick={button.action}
            title={button.tooltip}
          >
            {button.icon}
          </Button>
        ))}
        <div className="flex-1" />
        <Button
          variant="outline"
          onClick={onSave}
          disabled={!isDirty}
        >
          Save
        </Button>
      </div>
      <Tabs value={activeTab} onValueChange={(value) => setActiveTab(value as 'edit' | 'preview')} className="flex-1">
        <TabsList className="w-full justify-start border-b rounded-none">
          <TabsTrigger value="edit">Edit</TabsTrigger>
          <TabsTrigger value="preview">Preview</TabsTrigger>
        </TabsList>
        <TabsContent value="edit" className="flex-1 mt-0">
          <textarea
            value={content}
            onChange={(e) => {
              onChange(e.target.value);
              setIsDirty(true);
            }}
            className="w-full h-full p-4 resize-none focus:outline-none"
            placeholder="Start writing your journal entry..."
          />
        </TabsContent>
        <TabsContent value="preview" className="flex-1 mt-0 p-4 overflow-auto">
          <ReactMarkdown
            remarkPlugins={[remarkGfm]}
            components={{
              code({ node, className, children }) {
                const match = /language-(\w+)/.exec(className || '');
                return match ? (
                  <SyntaxHighlighter
                    style={vscDarkPlus as any}
                    language={match[1]}
                    PreTag="div"
                  >
                    {String(children).replace(/\n$/, '')}
                  </SyntaxHighlighter>
                ) : (
                  <code className={className}>
                    {children}
                  </code>
                );
              },
            }}
          >
            {content}
          </ReactMarkdown>
        </TabsContent>
      </Tabs>
    </div>
  );
} 