"use client"

import React from 'react';
import { useJournal } from '@/contexts/JournalContext';
import { Button } from '@/components/ui/button';
import { Plus } from 'lucide-react';

export function JournalWelcomeCard() {
  const { createEntry } = useJournal();

  const handleCreate = () => {
    const title = window.prompt('Enter journal title');
    if (title && title.trim()) {
      createEntry(title.trim());
    }
  };

  return (
    <div className="bg-white dark:bg-neutral-900 rounded-lg shadow p-6 flex items-center justify-between">
      <div>
        <h2 className="text-xl font-semibold text-foreground">Start Writing</h2>
        <p className="text-sm text-muted-foreground mt-1">Create a new journal entry to begin</p>
      </div>
      <Button
        onClick={handleCreate}
        className="bg-emerald-600 text-white hover:bg-emerald-700"
      >
        <Plus className="h-4 w-4 mr-2" />
        Create New Journal
      </Button>
    </div>
  );
} 